solution_code:
#include <iostream>

int double_it(int x) {
    std::cerr << "[trace] double_it x=" << x << "\n";
    return x * 2;
}

int process(int a, int b) {
    std::cerr << "[trace] process a=" << a << " b=" << b << "\n";
    return double_it(a) + b;
}

int main() {
    int a, b;
    std::cin >> a >> b;
    std::cout << process(a, b) << "\n";
    return 0;
}

