solution_code:
#include <iostream>

int triple_and_add(int a, int b) {
    std::cerr << "[trace] triple_and_add a=" << a << " b=" << b << "\n";
    int tripled = a * 3;
    std::cerr << "[trace] tripled=" << tripled << "\n";
    return tripled + b;
}

int main() {
    int a, b;
    std::cin >> a >> b;
    std::cout << triple_and_add(a, b) << "\n";
    return 0;
}
